sql:
SELECT SUM(present_attendance) AS total_attendance
FROM attendance_records
WHERE event_id = 0;

external_knowledge:
- "blooming with more than 70% of their petals unfurled" refers to events with an attendance percentage greater than 70%;
- "the year bloomed with the lectures of 1896" refers to the year 1896 where event types are filtered to only include lectures;
- The garden of knowledge is a metaphor for the educational events held.

sql:
SELECT sex, SUM(total_attendance) AS total_attendance, SUM(present_attendance) AS present_attendance
FROM attendance_records
GROUP BY sex;

SELECT type_name, AVG(default_duration) AS average_duration
FROM event_types
GROUP BY type_name;

SELECT event_id, SUM(total_attendance) AS total_attendees
FROM attendance_records
GROUP BY event_id;

SELECT COUNT(event_id) AS total_attendance
FROM events
WHERE year = 2022 AND event_type = 1;
